/**
 * Kimi API Client
 * Interface with Moonshot AI API
 */

import { env } from 'process';

// API Configuration. Kept as KimiClient for backwards compatibility; it can
// also point at any OpenAI-compatible gateway via OMK_API_* or CUSTOM_API_*.
const DEFAULT_BASE_URL = 'https://api.moonshot.cn/v1';
const DEFAULT_MODEL = 'kimi-k2-0711-preview';

// Types
export interface KimiMessage {
  role: 'system' | 'user' | 'assistant' | 'tool';
  content: string;
  tool_calls?: KimiToolCall[];
  tool_call_id?: string;
}

export interface KimiToolCall {
  id: string;
  type: 'function';
  function: {
    name: string;
    arguments: string;
  };
}

export interface KimiTool {
  type: 'function';
  function: {
    name: string;
    description: string;
    parameters: Record<string, unknown>;
  };
}

export interface KimiCompletionOptions {
  model?: string;
  messages: KimiMessage[];
  tools?: KimiTool[];
  temperature?: number;
  max_tokens?: number;
  stream?: boolean;
  reasoning_effort?: 'low' | 'medium' | 'high';
}

export interface KimiCompletionResponse {
  id: string;
  object: string;
  created: number;
  model: string;
  choices: {
    index: number;
    message: KimiMessage;
    finish_reason: string;
  }[];
  usage: {
    prompt_tokens: number;
    completion_tokens: number;
    total_tokens: number;
  };
}

export interface KimiStreamChunk {
  id: string;
  object: string;
  created: number;
  model: string;
  choices: {
    index: number;
    delta: Partial<KimiMessage>;
    finish_reason: string | null;
  }[];
}

// Error types
export class KimiAPIError extends Error {
  constructor(
    message: string,
    public statusCode?: number,
    public response?: unknown
  ) {
    super(message);
    this.name = 'KimiAPIError';
  }
}

export class KimiConfigError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'KimiConfigError';
  }
}

// Client class
export class KimiClient {
  private apiKey: string;
  private baseUrl: string;
  private defaultModel: string;

  constructor(options?: { 
    apiKey?: string; 
    baseUrl?: string; 
    model?: string;
  }) {
    this.apiKey = options?.apiKey || env.OMK_API_KEY || env.CUSTOM_API_KEY || env.KIMI_API_KEY || '';
    this.baseUrl = options?.baseUrl || env.OMK_API_BASE_URL || env.CUSTOM_API_BASE_URL || env.KIMI_BASE_URL || DEFAULT_BASE_URL;
    this.defaultModel = options?.model || env.OMK_MODEL || env.CUSTOM_API_MODEL || env.KIMI_MODEL || DEFAULT_MODEL;

    if (!this.apiKey) {
      throw new KimiConfigError(
        'An API key is required. Set OMK_API_KEY, CUSTOM_API_KEY, KIMI_API_KEY, or pass apiKey to the constructor.'
      );
    }
  }

  /**
   * Create a chat completion
   */
  async complete(options: KimiCompletionOptions): Promise<KimiCompletionResponse> {
    const url = `${this.baseUrl}/chat/completions`;
    
    const body = {
      model: options.model || this.defaultModel,
      messages: options.messages,
      tools: options.tools,
      temperature: options.temperature ?? 0.7,
      max_tokens: options.max_tokens ?? 4096,
      stream: false,
    };

    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${this.apiKey}`,
      },
      body: JSON.stringify(body),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new KimiAPIError(
        `API request failed: ${response.status} ${errorText}`,
        response.status,
        errorText
      );
    }

    return response.json() as Promise<KimiCompletionResponse>;
  }

  /**
   * Create a streaming chat completion
   */
  async *stream(options: KimiCompletionOptions): AsyncGenerator<KimiStreamChunk> {
    const url = `${this.baseUrl}/chat/completions`;
    
    const body = {
      model: options.model || this.defaultModel,
      messages: options.messages,
      tools: options.tools,
      temperature: options.temperature ?? 0.7,
      max_tokens: options.max_tokens ?? 4096,
      stream: true,
    };

    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${this.apiKey}`,
      },
      body: JSON.stringify(body),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new KimiAPIError(
        `API request failed: ${response.status} ${errorText}`,
        response.status,
        errorText
      );
    }

    const reader = response.body?.getReader();
    if (!reader) {
      throw new KimiAPIError('Response body is not readable');
    }

    const decoder = new TextDecoder();
    let buffer = '';

    try {
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() || '';

        for (const line of lines) {
          const trimmed = line.trim();
          if (!trimmed || trimmed === 'data: [DONE]') continue;
          
          if (trimmed.startsWith('data: ')) {
            try {
              const data = JSON.parse(trimmed.slice(6)) as KimiStreamChunk;
              yield data;
            } catch {
              // Skip invalid JSON
            }
          }
        }
      }
    } finally {
      reader.releaseLock();
    }
  }

