/**
 * OMK configuration loader.
 *
 * Precedence is intentionally simple:
 * CLI/explicit options > project .omk/config.toml > global ~/.omk/config.toml > env/defaults.
 */

import { existsSync, readFileSync } from 'fs';
import { join } from 'path';
import { homedir } from 'os';
import TOML from '@iarna/toml';
import { ProviderConfig, ProviderType, ReasoningEffort } from './providers/types.js';

export interface OMKConfig {
  provider?: ProviderType;
  model?: string;
  apiKey?: string;
  baseUrl?: string;
  apiKeyEnv?: string;
  reasoning?: ReasoningEffort;
  headers?: Record<string, string>;
  providers?: Record<string, Partial<ProviderConfig>>;
  models?: Record<string, string>;
}

function readConfig(path: string): OMKConfig {
  if (!existsSync(path)) return {};
  try {
    const content = readFileSync(path, 'utf-8').replace(/^\uFEFF/, '');
    return TOML.parse(content) as OMKConfig;
  } catch (err) {
    throw new Error(`Failed to parse config ${path}: ${err instanceof Error ? err.message : String(err)}`);
  }
}

function mergeConfig(base: OMKConfig, override: OMKConfig): OMKConfig {
  return {
    ...base,
    ...override,
    headers: {
      ...(base.headers ?? {}),
      ...(override.headers ?? {}),
    },
    providers: {
      ...(base.providers ?? {}),
      ...(override.providers ?? {}),
    },
    models: {
      ...(base.models ?? {}),
      ...(override.models ?? {}),
    },
  };
}

function definedOnly<T extends Record<string, unknown>>(input: T): Partial<T> {
  return Object.fromEntries(
    Object.entries(input).filter(([, value]) => value !== undefined)
  ) as Partial<T>;
}

function normalizeProviderOverride(config: Partial<ProviderConfig>): Partial<ProviderConfig> {
  const normalized = { ...config };
  const maybeKey = normalized.apiKeyEnv?.trim();

  if (maybeKey && /^(sk-|or-|pk-)/i.test(maybeKey)) {
    normalized.apiKey = maybeKey;
    delete normalized.apiKeyEnv;
  }

  return normalized;
}

export function loadOMKConfig(cwd: string = process.cwd()): OMKConfig {
  const globalPath = join(homedir(), '.omk', 'config.toml');
  const projectPath = join(cwd, '.omk', 'config.toml');
  return mergeConfig(readConfig(globalPath), readConfig(projectPath));
}

export function resolveProviderConfig(
  requested: Partial<ProviderConfig> = {},
  cwd: string = process.cwd()
): ProviderConfig {
  const fileConfig = loadOMKConfig(cwd);
  const cleanRequested = definedOnly(requested as Record<string, unknown>) as Partial<ProviderConfig>;
  const requestedType = cleanRequested.type ?? fileConfig.provider ?? 'auto';
  const providerOverride = normalizeProviderOverride(fileConfig.providers?.[requestedType] ?? {});
  const normalizedFileConfig = normalizeProviderOverride(fileConfig as Partial<ProviderConfig>);

  return {
    type: requestedType,
    reasoning: fileConfig.reasoning,
    model: fileConfig.model,
    apiKey: normalizedFileConfig.apiKey,
    baseUrl: normalizedFileConfig.baseUrl,
    apiKeyEnv: normalizedFileConfig.apiKeyEnv,
    ...providerOverride,
    ...cleanRequested,
    headers: {
      ...(fileConfig.headers ?? {}),
      ...(providerOverride.headers ?? {}),
      ...(cleanRequested.headers ?? {}),
    },
  };
}

export function parseHeaderFlags(values: string[] = []): Record<string, string> {
  const headers: Record<string, string> = {};
  for (const raw of values) {
    const idx = raw.indexOf('=');
    if (idx <= 0) continue;
    headers[raw.slice(0, idx).trim()] = raw.slice(idx + 1).trim();
  }
  return headers;
}

/**
 * Codebase Indexer - For large projects (100K+ lines)
 * Indexes files for fast search and smart context selection
 */

import { existsSync, readFileSync, statSync, readdirSync } from 'fs';
import { join, relative, extname, dirname } from 'path';

export interface Symbol {
  name: string;
  type: 'class' | 'function' | 'method' | 'interface' | 'type' | 'variable' | 'const' | 'enum';
  line: number;
  column: number;
  signature?: string;
  documentation?: string;
  isExported: boolean;
}

export interface FileIndex {
  path: string;
  relativePath: string;
  size: number;
  lines: number;
  language: string;
  lastModified: number;
  contentHash: string;
  symbols: Symbol[];
  imports: string[];
  exports: string[];
  dependencies: string[];
  dependents: string[];
}

export interface RepositoryMap {
  totalFiles: number;
  totalLines: number;
  totalSymbols: number;
  languages: Record<string, { files: number; lines: number; percentage: number }>;
  modules: ModuleInfo[];
  entryPoints: string[];
  keyFiles: string[];
  largestFiles: string[];
  mostImported: string[];
}

export interface ModuleInfo {
  name: string;
  path: string;
  files: number;
  lines: number;
  entryPoints: string[];
  dependencies: string[];
}

export class CodebaseIndexer {
  private cwd: string;
  private index: Map<string, FileIndex> = new Map();
  private isIndexing: boolean = false;

  private readonly CODE_EXTENSIONS = new Set([
    '.ts', '.tsx', '.js', '.jsx', '.py', '.rs', '.go', '.java', '.kt',
    '.c', '.cpp', '.h', '.hpp', '.rb', '.php', '.swift', '.scala',
    '.cs', '.fs', '.ex', '.exs',
  ]);

  private readonly SKIP_DIRS = new Set([
    'node_modules', '.git', 'dist', 'build', 'target', '.next', '.nuxt',
    'coverage', '.cache', 'vendor', '__pycache__', '.tox', '.eggs',
  ]);

  constructor(cwd: string) {
    this.cwd = cwd;
  }

  async buildIndex(progressCallback?: (current: number, total: number, file: string) => void): Promise<RepositoryMap> {
    if (this.isIndexing) throw new Error('Indexing already in progress');
    
    this.isIndexing = true;
    this.index.clear();

    try {
      const files = await this.findCodeFiles();
      const total = files.length;

      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        try {
          await this.indexFile(file);
          if (progressCallback) progressCallback(i + 1, total, file);
        } catch (err) {
          // Skip failed files
        }
      }

      this.buildDependencyGraph();
      return this.generateRepositoryMap();
    } finally {
      this.isIndexing = false;
    }
  }

  private async findCodeFiles(dir: string = this.cwd): Promise<string[]> {
    const files: string[] = [];
    const entries = readdirSync(dir, { withFileTypes: true });
    
    for (const entry of entries) {
      const fullPath = join(dir, entry.name);
      
      if (entry.isDirectory()) {
        if (!this.SKIP_DIRS.has(entry.name) && !entry.name.startsWith('.')) {
          files.push(...await this.findCodeFiles(fullPath));
        }
      } else if (this.CODE_EXTENSIONS.has(extname(entry.name))) {
        files.push(fullPath);
      }
    }
    
    return files;
  }

  private async indexFile(filePath: string): Promise<void> {
    const content = readFileSync(filePath, 'utf-8');
    const stats = statSync(filePath);
    const language = this.detectLanguage(filePath);
    
    this.index.set(filePath, {
      path: filePath,
      relativePath: relative(this.cwd, filePath),
      size: stats.size,
      lines: content.split('\n').length,
      language,
      lastModified: stats.mtimeMs,
      contentHash: this.simpleHash(content),
      symbols: this.extractSymbols(content, language),
      imports: this.extractImports(content, language),
      exports: this.extractExports(content, language),
      dependencies: [],
      dependents: [],
    });
  }

  private detectLanguage(filePath: string): string {
    const ext = extname(filePath);
    const map: Record<string, string> = {
      '.ts': 'TypeScript', '.tsx': 'TypeScript',
      '.js': 'JavaScript', '.jsx': 'JavaScript',
      '.py': 'Python', '.rs': 'Rust', '.go': 'Go',
      '.java': 'Java', '.kt': 'Kotlin',
      '.c': 'C', '.cpp': 'C++', '.h': 'C/C++', '.hpp': 'C++',
      '.rb': 'Ruby', '.php': 'PHP', '.swift': 'Swift',
    };
    return map[ext] || 'Unknown';
  }

  private extractSymbols(content: string, language: string): Symbol[] {
    const symbols: Symbol[] = [];
    const lines = content.split('\n');

    const patterns: Record<string, RegExp[]> = {
      TypeScript: [
        /^(export\s+)?(class|interface|type|enum|function)\s+(\w+)/,
        /^(export\s+)?const\s+(\w+)\s*[:=]/,
      ],
      Python: [/^class\s+(\w+)/, /^def\s+(\w+)/],
      Rust: [/^pub\s+(fn|struct|enum|trait)\s+(\w+)/],
    };

    const langPatterns = patterns[language] || patterns.TypeScript || [];

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i].trim();
      for (const pattern of langPatterns) {
        const match = line.match(pattern);
        if (match) {
          symbols.push({
            name: match[match.length - 1],
            type: line.includes('class') ? 'class' : 
                  line.includes('interface') ? 'interface' : 'function',
            line: i + 1,
            column: line.indexOf(match[match.length - 1]) + 1,
            isExported: line.startsWith('export') || line.startsWith('pub'),
          });
          break;
        }
      }
    }

    return symbols;
  }

  private extractImports(content: string, language: string): string[] {
    const imports: string[] = [];
    const patterns: Record<string, RegExp> = {
      TypeScript: /import\s+.*?\s+from\s+['"]([^'"]+)['"]/g,
      Python: /^(?:from|import)\s+(\w+)/gm,
    };

