/**
 * MCP Server for OMK
 * Exposes OMK state and tools via Model Context Protocol
 */

import { createServer } from 'http';
import { readFileSync, existsSync } from 'fs';
import { join } from 'path';
import { 
  MCPRequest, 
  MCPResponse, 
  MCPServerInfo, 
  MCPResource, 
  MCPTool,
  MCPPrompt 
} from './types.js';
import { listActiveModes, listTasks, readNotepad, readProjectMemory } from '../state/index.js';

export class OMKMCPServer {
  private port: number;
  private server: ReturnType<typeof createServer> | null = null;

  constructor(port: number = 3000) {
    this.port = port;
  }

  start(): void {
    this.server = createServer((req, res) => {
      // CORS headers
      res.setHeader('Access-Control-Allow-Origin', '*');
      res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
      res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

      if (req.method === 'OPTIONS') {
        res.writeHead(200);
        res.end();
        return;
      }

      if (req.method !== 'POST') {
        res.writeHead(405);
        res.end(JSON.stringify({ error: 'Method not allowed' }));
        return;
      }

      let body = '';
      req.on('data', chunk => body += chunk);
      req.on('end', async () => {
        try {
          const request = JSON.parse(body) as MCPRequest;
          const response = await this.handleRequest(request);
          res.setHeader('Content-Type', 'application/json');
          res.writeHead(200);
          res.end(JSON.stringify(response));
        } catch (err) {
          const errorResponse: MCPResponse = {
            jsonrpc: '2.0',
            id: 0,
            error: {
              code: -32700,
              message: 'Parse error',
            },
          };
          res.writeHead(400);
          res.end(JSON.stringify(errorResponse));
        }
      });
    });

    this.server.listen(this.port, () => {
      console.log(`[OMK MCP Server] Running on port ${this.port}`);
    });
  }

  stop(): void {
    if (this.server) {
      this.server.close();
      this.server = null;
    }
  }

  private async handleRequest(request: MCPRequest): Promise<MCPResponse> {
    const { method, params, id } = request;

    switch (method) {
      case 'initialize':
        return this.handleInitialize(id);
      
      case 'resources/list':
        return this.handleListResources(id);
      
      case 'resources/read':
        return this.handleReadResource(id, params as { uri: string });
      
      case 'tools/list':
        return this.handleListTools(id);
      
      case 'tools/call':
