/**
 * Swarm Engine - Parallel exploration with voting/consensus
 */

import { runModelPrompt, ModelRunOptions } from '../model-runner.js';
import {
  createTeam,
  startWorkers,
  assignTask,
  shutdownTeam,
  getTeamStatus,
  isTmuxAvailable,
  isInTmux,
  capturePane,
} from '../../team/index.js';

export class SwarmEngine {
  private cwd: string;
  private options: ModelRunOptions;

  constructor(
    cwd: string,
    options: ModelRunOptions = {}
  ) {
    this.cwd = cwd;
    this.options = options;
  }

  async run(task: string, agentCount: number = 3, voteMethod: string = 'ranking'): Promise<void> {
    if (!isTmuxAvailable() || !isInTmux()) {
      console.log('[OMK Swarm] tmux unavailable. Running simulated swarm in-process.\n');
      await this.runSimulated(task, agentCount, voteMethod);
      return;
    }

    const teamName = `swarm-${Date.now()}`;
    console.log(`\n[OMK Swarm] Spawning ${agentCount} agents for: ${task}\n`);

    await createTeam(teamName, agentCount, 'explorer', task, this.cwd);
    const state = await startWorkers(teamName, this.cwd);

    // Each worker gets a slightly different angle
    const angles = await this.generateAngles(task, state.workers.length);
    for (let i = 0; i < state.workers.length; i++) {
      const prompt = `Explore this problem from this angle: ${angles[i] || 'General exploration'}\n\nProblem: ${task}\n\nProvide your best solution and reasoning.`;
      await assignTask(teamName, state.workers[i].id, prompt, this.cwd);
    }

    console.log('[OMK Swarm] Waiting for explorations...\n');
    await this.poll(teamName, 15);

    const explorations = state.workers.map((w) => ({
      agent: w.id,
      output: w.paneId ? capturePane(w.paneId, 30) : '',
    }));

    console.log('\n[OMK Swarm] Voting and consolidating...\n');
    await this.runVote(task, explorations, voteMethod);

    await shutdownTeam(teamName, this.cwd);
  }

  private async runSimulated(task: string, agentCount: number, voteMethod: string): Promise<void> {
    const explorations = [];
    for (let i = 0; i < agentCount; i++) {
      const angle = await runModelPrompt(
        `Generate a unique exploration angle for: ${task}\nRespond with one sentence describing the angle.`,
        this.options
      );
      const res = await runModelPrompt(
        `Explore this problem from the angle: ${angle.stdout}\n\n${task}\n\nProvide your best solution.`,
        this.options
      );
      explorations.push({ agent: `agent-${i + 1}`, output: res.stdout });
    }
    await this.runVote(task, explorations, voteMethod);
  }

  private async generateAngles(task: string, count: number): Promise<string[]> {
    const res = await runModelPrompt(
      `Generate ${count} different angles to explore this problem. Return as numbered list:\n\n${task}`,
      this.options
    );
    return res.stdout
      .split('\n')
      .map((l) => l.match(/^\s*(?:\d+[.):-]\s+|-\s+)(.*)$/)?.[1])
      .filter(Boolean) as string[];
  }

  private async runVote(
    task: string,
    explorations: { agent: string; output: string }[],
    voteMethod: string
  ): Promise<void> {
    const votePrompt = `You are the Swarm Leader. Review these ${explorations.length} agent explorations and produce a consensus result.

Task: ${task}
Vote method: ${voteMethod}

${explorations.map((e) => `## ${e.agent}\n${e.output}`).join('\n\n')}

Provide:
1. Best option (with reasoning)
2. Confidence score (1-10)
3. Any dissenting views worth noting`;

    const result = await runModelPrompt(votePrompt, this.options);
    console.log(result.stdout);
  }

  private async poll(teamName: string, maxMinutes: number): Promise<void> {
    const deadline = Date.now() + maxMinutes * 60 * 1000;
    while (Date.now() < deadline) {
      const state = await getTeamStatus(teamName, this.cwd);
      if (!state) break;
      const allDone = state.workers.every(
        (w) => w.status === 'completed' || w.status === 'error'
      );
      if (allDone) break;
      await new Promise((r) => setTimeout(r, 5000));
    }
  }
}

/**
 * Team Engine - Coordinated multi-agent execution via tmux
 */

import { runModelPrompt, runModelToolLoop, ModelRunOptions } from '../model-runner.js';
import {
  createTeam,
  startWorkers,
  assignTask,
  shutdownTeam,
  getTeamStatus,
  isTmuxAvailable,
  isInTmux,
  capturePane,
  Worker,
} from '../../team/index.js';

export class TeamEngine {
  private cwd: string;
  private options: ModelRunOptions;

  constructor(
    cwd: string,
    options: ModelRunOptions = {}
  ) {
    this.cwd = cwd;
    this.options = options;
  }

  async run(task: string, workerCount: number = 3): Promise<void> {
    if (!isTmuxAvailable()) {
      console.log('tmux is not available. Running team lanes in-process instead.');
      await this.runInProcess(task, workerCount);
      return;
    }
    if (!isInTmux()) {
      console.log('Not inside tmux. Running team lanes in-process instead.');
      await this.runInProcess(task, workerCount);
      return;
    }

    const teamName = `team-${Date.now()}`;
    console.log(`\n[OMK Team] Creating team: ${teamName} with ${workerCount} workers\n`);

    const state = await createTeam(teamName, workerCount, 'generalist', task, this.cwd);
    await startWorkers(teamName, this.cwd);

    // Break task into subtasks via the configured provider.
    console.log('[OMK Team] Decomposing task into subtasks...\n');
    const planResult = await runModelPrompt(
      `Break this task into ${workerCount} independent subtasks:\n\n${task}\n\nReturn as numbered list.`,
      this.options
    );

    const subtasks = this.parseSubtasks(planResult.stdout);

    // Assign to workers
    for (let i = 0; i < Math.min(subtasks.length, state.workers.length); i++) {
      const worker = state.workers[i];
      const subtask = subtasks[i];
      console.log(`[OMK Team] Assigning to ${worker.id}: ${subtask.slice(0, 80)}...`);
      await assignTask(teamName, worker.id, subtask, this.cwd);
    }

    // Poll for completion
    console.log('\n[OMK Team] Waiting for workers to complete...\n');
    await this.pollUntilDone(teamName, state.workers, 30);

    // Collect results from panes
    const results = state.workers.map((w) => ({
      worker: w.id,
      output: w.paneId ? capturePane(w.paneId, 30) : '',
    }));

    // Consolidate via the configured provider.
    console.log('\n[OMK Team] Consolidating results...\n');
    const consolidatePrompt = `Consolidate these worker outputs into a coherent final result:\n\n${results
      .map((r) => `## ${r.worker}\n${r.output}`)
      .join('\n\n')}`;

    await runModelPrompt(consolidatePrompt, this.options);

    await shutdownTeam(teamName, this.cwd);
    console.log('\n[OMK Team] Done.\n');
  }

  private async runInProcess(task: string, workerCount: number): Promise<void> {
    console.log(`\n[OMK Team] In-process team: ${workerCount} lanes\n`);
    const planResult = await runModelPrompt(
      `Break this task into ${workerCount} independent subtasks:\n\n${task}\n\nReturn as numbered list.`,
      this.options
    );
    const subtasks = this.parseSubtasks(planResult.stdout).slice(0, workerCount);
    const results: { worker: string; output: string }[] = [];

    for (let i = 0; i < Math.max(subtasks.length, 1); i++) {
      const subtask = subtasks[i] ?? task;
      console.log(`\n[OMK Team] Lane ${i + 1}: ${subtask}\n`);
      const result = await runModelToolLoop(
        `You are team worker ${i + 1}. Complete this bounded lane and report concise results.\n\n${subtask}`,
        this.cwd,
        this.options
      );
      results.push({ worker: `lane-${i + 1}`, output: result.stdout });
    }

    await runModelPrompt(
      `Consolidate these team lane outputs into one final result:\n\n${results
        .map((r) => `## ${r.worker}\n${r.output}`)
        .join('\n\n')}`,
      this.options
    );
  }

  private parseSubtasks(text: string): string[] {
    const lines = text.split('\n');
    const tasks: string[] = [];
    for (const line of lines) {
      const match = line.match(/^\s*(?:\d+[.):-]\s+|-\s+)(.*)$/);
      if (match && match[1].trim()) {
        tasks.push(match[1].trim());
      }
    }
    return tasks.length > 0 ? tasks : [text];
  }

  private async pollUntilDone(teamName: string, workers: Worker[], maxMinutes: number): Promise<void> {
    const deadline = Date.now() + maxMinutes * 60 * 1000;
    while (Date.now() < deadline) {
      const state = await getTeamStatus(teamName, this.cwd);
      if (!state) break;
      const allDone = state.workers.every(
        (w) => w.status === 'completed' || w.status === 'error'
      );
      if (allDone) break;
      await new Promise((r) => setTimeout(r, 5000));
    }
  }
}

/**
 * UltraQA Engine - Intensive QA cycling for critical code
 */

import { runModelPrompt, runModelToolLoop, ModelRunOptions } from '../model-runner.js';
import { existsSync } from 'fs';
import { join } from 'path';

export class UltraQAEngine {
  private cwd: string;
  private options: ModelRunOptions;

  constructor(
    cwd: string,
    options: ModelRunOptions = {}
  ) {
    this.cwd = cwd;
    this.options = options;
  }

  async run(targetPath?: string): Promise<void> {
    const target = targetPath || '.';
    console.log('\n[OMK UltraQA] Starting QA cycle\n');

    const report: string[] = ['# UltraQA Report\n'];
    const timestamp = new Date().toISOString();
    report.push(`**Date:** ${timestamp}\n`);
    report.push(`**Target:** ${target}\n\n`);

    // Phase 1: Automated checks
    console.log('## Phase 1: Automated Checks\n');
    const automated = await this.runAutomatedChecks(target);
    report.push('## Phase 1: Automated Checks\n' + automated + '\n');

    // Phase 2: AI Review
    console.log('## Phase 2: AI Review\n');
    const review = await this.runAIReview(target);
    report.push('## Phase 2: AI Review\n' + review + '\n');

    // Phase 3: Edge Cases
    console.log('## Phase 3: Edge Cases\n');
    const edgeCases = await this.runEdgeCases(target);
    report.push('## Phase 3: Edge Cases\n' + edgeCases + '\n');

    // Phase 4: Final Verify
    console.log('## Phase 4: Final Verification\n');
    const final = await this.runFinalVerify(target);
    report.push('## Phase 4: Final Verification\n' + final + '\n');

    // Save report
    const reportDir = join(this.cwd, '.omk', 'qa-reports');
    const fs = await import('fs');
    if (!existsSync(reportDir)) fs.mkdirSync(reportDir, { recursive: true });
    const reportPath = join(reportDir, `ultraqa-${Date.now()}.md`);
    fs.writeFileSync(reportPath, report.join('\n'));

    console.log(`\n[OMK UltraQA] Report saved: ${reportPath}\n`);
  }

  private async runAutomatedChecks(target: string): Promise<string> {
    const results: string[] = [];

    // Lint
    try {
      const pkgPath = join(this.cwd, 'package.json');
      if (existsSync(pkgPath)) {
        const res = await this.runCommand('npm run lint --if-present');
        results.push(`Lint: ${res}`);
      }
    } catch {
      results.push('Lint: skipped or failed');
    }

    // Type check
    try {
      const tsConfig = join(this.cwd, 'tsconfig.json');
      if (existsSync(tsConfig)) {
        const res = await this.runCommand('npx tsc --noEmit');
        results.push(`Type check: ${res}`);
      }
    } catch {
      results.push('Type check: skipped or failed');
    }

    // Tests
    try {
      const res = await this.runCommand('npm test --if-present');
      results.push(`Tests: ${res}`);
    } catch {
      results.push('Tests: skipped or failed');
    }

    return results.join('\n');
  }

  private async runAIReview(target: string): Promise<string> {
    const prompt = `Review the code at ${target} for quality, security, and performance issues.
Look for obvious bugs, anti-patterns, missing error handling, and hardcoded secrets.
Provide a concise summary.`;
    const result = await runModelToolLoop(prompt, this.cwd, this.options, { maxIterations: 3 });
    return result.stdout;
  }

  private async runEdgeCases(target: string): Promise<string> {
    const prompt = `For the code at ${target}, identify boundary conditions and edge cases that should be tested.
Generate test cases (pseudocode or actual code) for the top 3 edge cases.`;
    const result = await runModelToolLoop(prompt, this.cwd, this.options, { maxIterations: 3 });
    return result.stdout;
  }

  private async runFinalVerify(target: string): Promise<string> {
    const prompt = `Perform a final verification of ${target}.
Check: documentation completeness, E2E sanity, deployment readiness.
Give a PASS or FAIL verdict with bullet points.`;
    const result = await runModelPrompt(prompt, this.options);
    return result.stdout;
  }

  private async runCommand(cmd: string): Promise<string> {
    const { execSync } = await import('child_process');
    try {
      return execSync(cmd, { cwd: this.cwd, encoding: 'utf-8' });
    } catch (err: any) {
      return err.stdout || err.message || 'failed';
    }
  }
}

/**
 * Ultrawork Engine - High-throughput parallel execution
 * Similar to Team but with more workers and less coordination overhead
 */

import { runModelPrompt, runModelToolLoop, ModelRunOptions } from '../model-runner.js';
import {
  createTeam,
  startWorkers,
  assignTask,
  shutdownTeam,
  getTeamStatus,
  isTmuxAvailable,
  isInTmux,
  capturePane,
} from '../../team/index.js';

export class UltraworkEngine {
  private cwd: string;
  private options: ModelRunOptions;

  constructor(
    cwd: string,
    options: ModelRunOptions = {}
  ) {
    this.cwd = cwd;
    this.options = options;
  }

  async run(task: string, workerCount: number = 5): Promise<void> {
    if (!isTmuxAvailable() || !isInTmux()) {
      // Fallback: run in-process batch
      console.log(`\n[OMK Ultrawork] tmux unavailable. Running in-process batch mode.\n`);
      await this.runInProcess(task);
      return;
    }

    const teamName = `ulw-${Date.now()}`;
    console.log(`\n[OMK Ultrawork] Spawning ${workerCount} workers for: ${task}\n`);

    await createTeam(teamName, workerCount, 'batch-worker', task, this.cwd);
    const state = await startWorkers(teamName, this.cwd);

    // Shard task
    const shards = await this.shardTask(task, state.workers.length);

    // Assign in parallel
    await Promise.all(
      state.workers.map((w, i) =>
        assignTask(teamName, w.id, shards[i] || 'Assist with remaining work', this.cwd)
      )
    );

    console.log('[OMK Ultrawork] All tasks dispatched. Waiting...\n');
    await this.poll(teamName, 20);

    const results = state.workers.map((w) => ({
      worker: w.id,
      output: w.paneId ? capturePane(w.paneId, 20) : '',
    }));

    console.log('\n[OMK Ultrawork] Aggregating results...\n');
    const aggregatePrompt = `Aggregate these parallel worker outputs. Summarize findings and next steps:\n\n${results
      .map((r) => `## ${r.worker}\n${r.output}`)
      .join('\n\n')}`;

    await runModelPrompt(aggregatePrompt, this.options);

    await shutdownTeam(teamName, this.cwd);
  }

  private async runInProcess(task: string): Promise<void> {
    // Break into batches and run sequentially through the configured provider.
    const plan = await runModelPrompt(
      `Split this task into 3-5 independent batches:\n\n${task}\n\nReturn as numbered list only.`,
      this.options
    );

    const batches = plan.stdout
      .split('\n')
      .map((l) => l.match(/^\s*(?:\d+[.):-]\s+|-\s+)(.*)$/)?.[1])
      .filter(Boolean) as string[];

    const outputs: string[] = [];
    for (let i = 0; i < batches.length; i++) {
      console.log(`\n[OMK Ultrawork] Batch ${i + 1}/${batches.length}: ${batches[i]}\n`);
      const res = await runModelToolLoop(batches[i], this.cwd, this.options, { maxIterations: 3 });
      outputs.push(res.stdout);
    }

    const final = await runModelPrompt(
      `Synthesize these batch outputs into a single coherent result:\n\n${outputs
        .map((o, i) => `## Batch ${i + 1}\n${o}`)
        .join('\n\n')}`,
      this.options
    );
    console.log(final.stdout);
  }

  private async shardTask(task: string, count: number): Promise<string[]> {
    const res = await runModelPrompt(
      `Split this task into exactly ${count} independent shards. Return as numbered list 1-${count}:\n\n${task}`,
      this.options
    );
    const shards = res.stdout
      .split('\n')
      .map((l) => l.match(/^\s*(?:\d+[.):-]\s+|-\s+)(.*)$/)?.[1])
      .filter(Boolean) as string[];
    return shards.length >= count ? shards.slice(0, count) : Array(count).fill(task);
  }

  private async poll(teamName: string, maxMinutes: number): Promise<void> {
    const deadline = Date.now() + maxMinutes * 60 * 1000;
    while (Date.now() < deadline) {
      const state = await getTeamStatus(teamName, this.cwd);
      if (!state) break;
      const allDone = state.workers.every(
        (w) => w.status === 'completed' || w.status === 'error'
      );
      if (allDone) break;
      await new Promise((r) => setTimeout(r, 5000));
    }
  }
}

